import React, { useState, useEffect } from 'react';
import './CommandeForm.css';

const CommandeForm = ({ selectedCommande, onSuccess }) => {
  const [formData, setFormData] = useState({
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });

  useEffect(() => {
    if (selectedCommande) {
      // Extrait les champs sauf idCOM car on ne le modifie pas
      const { idCOM, ...rest } = selectedCommande;
      setFormData(rest);
    } else {
      resetForm();
    }
  }, [selectedCommande]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      codeCli: '',
      codeArt: '',
      dateCom: '',
      QteCom: ''
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const method = selectedCommande ? 'PUT' : 'POST';
    const url = selectedCommande
      ? `http://localhost:3001/commandes/${selectedCommande.idCOM}`
      : 'http://localhost:3001/commandes';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      if (!selectedCommande) resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  const handleDelete = async () => {
    if (!selectedCommande) return;

    const confirmDelete = window.confirm('Supprimer cette commande ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${selectedCommande.idCOM}`, {
        method: 'DELETE'
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="commande-form">
      {selectedCommande && (
        <div>
          <label>idCOM :</label>
          <input type="text" value={selectedCommande.idCOM} readOnly />
        </div>
      )}

      <input
        name="codeCli"
        placeholder="Code Client"
        value={formData.codeCli}
        onChange={handleChange}
        required
      />
      <input
        name="codeArt"
        placeholder="Code Article"
        value={formData.codeArt}
        onChange={handleChange}
        required
      />
      <input
        type="date"
        name="dateCom"
        placeholder="Date de commande"
        value={formData.dateCom}
        onChange={handleChange}
        required
      />
      <input
        type="number"
        name="QteCom"
        placeholder="Quantité"
        value={formData.QteCom}
        onChange={handleChange}
        required
      />

      <button type="submit">
        {selectedCommande ? 'Modifier' : 'Ajouter'}
      </button>
      {selectedCommande && (
        <button type="button" onClick={handleDelete}>
          Supprimer
        </button>
      )}
    </form>
  );
};

export default CommandeForm;
